{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPsPbtFDr81J1qfQrpC1VL4"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"Pd7kH-C6infJ"},"outputs":[],"source":["import steamlit as st\n","from joblib import load\n","import numpy as np\n","\n","#load the model\n","model = load('linear_regression_model.joblib')\n","\n","#create a simple user input\n","user_input = st.number_input ('Enter house size: ', min_value= 100,\n","                              max_value = 10000, step = 50)\n","\n","#reshape the input for the model\n","input_array = np.array([user_input]).reshape(-1, 1)\n","\n","#predict the house price\n","if st.button('Predict Price'):\n","  predicted_price = model.predict(input_array)\n","  st.write(f\"The predicted house price is: ${predicted_price[0]:.2f}\")"]}]}